var sel = (Tekla.Structures.Model.ModelObjectSelector)model.GetModelObjectSelector();

// #5: list drawings + their status
var drawingResults = new System.Collections.Generic.List<object>();
int drawingTotal = 0;
try {
    var dh = new Tekla.Structures.Drawing.DrawingHandler();
    if (dh != null && dh.GetConnectionStatus()) {
        var drawEnum = dh.GetDrawings();
        while (drawEnum.MoveNext()) {
            var d = (Tekla.Structures.Drawing.Drawing)drawEnum.Current;
            drawingTotal++;
            if (drawingResults.Count < 5) {
                drawingResults.Add(new {
                    name = d.Name,
                    title1 = d.Title1,
                    is_ready = d.IsReadyForIssue
                });
            }
        }
    }
} catch (Exception ex) {
    drawingResults.Add(new { error = ex.GetType().Name + ": " + ex.Message });
}

// #7: simple horizontal beam from (0,2000,0) to (3000,2000,0) IPE300 S355
var horizBeam = new Tekla.Structures.Model.Beam(new Tekla.Structures.Geometry3d.Point(0, 2000, 0), new Tekla.Structures.Geometry3d.Point(3000, 2000, 0));
horizBeam.Profile.ProfileString = "IPE300";
horizBeam.Material.MaterialString = "S355";
horizBeam.Class = "1";
horizBeam.Name = "PROMPT 7 HORIZONTAL BEAM";
bool ok7 = horizBeam.Insert();

// #9: set UDA aware_lot=L1 on all parts with phase=1
var partsEnum = sel.GetAllObjectsWithType(Tekla.Structures.Model.ModelObject.ModelObjectEnum.BEAM);
int udaWritten9 = 0;
while (partsEnum.MoveNext()) {
    var part = (Tekla.Structures.Model.Part)partsEnum.Current;
    Tekla.Structures.Model.Phase ph;
    part.GetPhase(out ph);
    if (ph != null && ph.PhaseNumber == 1) {
        if (part.SetUserProperty("aware_lot", "L1")) udaWritten9++;
    }
}

// #10: stamp UDA last_audit with ISO-date on all parts (no selection on Tekla side)
string today = System.DateTime.UtcNow.ToString("yyyy-MM-dd");
var partsEnum10 = sel.GetAllObjectsWithType(Tekla.Structures.Model.ModelObject.ModelObjectEnum.BEAM);
int udaWritten10 = 0;
while (partsEnum10.MoveNext()) {
    var part = (Tekla.Structures.Model.Part)partsEnum10.Current;
    if (part.SetUserProperty("last_audit", today)) udaWritten10++;
}

// #16: numbering — Tekla 2026 doesn't expose programmatic trigger; report API gap
bool numberingOk = Tekla.Structures.Model.Operations.Operation.IsNumberingUpToDateAll();

return new {
    p5_drawings_total = drawingTotal,
    p5_drawings_sample = drawingResults,
    p7_beam_inserted = ok7,
    p7_beam_guid = horizBeam.Identifier.GUID.ToString(),
    p9_uda_aware_lot_count = udaWritten9,
    p10_uda_last_audit_count = udaWritten10,
    p10_today = today,
    p16_numbering_up_to_date = numberingOk,
    p16_note = "Tekla 2026 catalog has no programmatic numbering trigger; only IsNumberingUpToDate query. UI-only feature."
};
